cd /tmp/sv-27ec10cd8d4e49a0bf755946eb7afa3e/advanced-multi-complexity && dotnet package list --format json 2>/dev/null | python3 -m json.tool > after-cpm-packages.json && python3 -c "
import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: {project_basename: {(framework, pkg_id): (requested, resolved)}}
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (name, fw['framework'], pkg['id'])
                lookup[key] = (pkg['requestedVersion'], pkg['resolvedVersion'])
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    proj, fw, pkg = k
    if k in b and k in a:
        br, bv = b[k]
        ar, av = a[k]
        if bv != av:
            changes.append((proj, fw, pkg, bv, av, 'Aligned to highest version'))
        elif br != ar:
            changes.append((proj, fw, pkg, bv, av, 'Version centralized (same resolved)'))
        else:
            unchanged.append((proj, fw, pkg, bv))
    elif k in b and k not in a:
        br, bv = b[k]
        changes.append((proj, fw, pkg, bv, '-', 'Removed'))
    else:
        ar, av = a[k]
        changes.append((proj, fw, pkg, '-', av, 'Added'))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]} ({c[1]}) | {c[2]} | {c[3]} -> {c[4]} | {c[5]}')
else:
    print('  None')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'  {u[0]} ({u[1]}) | {u[2]} | {u[3]}')
"

